INSERT INTO public.projects (id,organization_id,name,color,created_at,updated_at,local_working_directory,everhour_project_id) VALUES ('dddddddd-dddd-4ddd-8ddd-ddddddddddd1', 1, 'Overlord Core', '#6b7280', '2026-02-18T14:32:28.970Z', '2026-02-18T14:32:28.970Z', NULL, NULL);
INSERT INTO public.tickets (id,ticket_sequence,title,objective,context,constraints,available_tools,acceptance_criteria,output_format,assigned_agent,priority,status,created_by,created_at,updated_at,board_position,organization_id,project_id) VALUES ('44444444-4444-4444-8444-444444444441', 14978343, 'Implement protocol attach flow', 'Create endpoint flow so Claude Code and ChatGPT can attach to tickets and retrieve structured context.', 'MVP focuses on protocol calls and deterministic event logs. Reuse shared state and ticket events for auditability.', 'No hidden state in clients. Every significant step writes to ticket_events.', 'REST API, MCP server, Supabase SQL, Next.js app router', 'attach returns ticket spec + history + relevant shared state and creates/updates agent session heartbeat.', 'API handlers, tests, and a short implementation summary artifact.', 'Claude Code', 'high', 'execute', '11111111-1111-4111-8111-111111111111', '2026-02-18T14:32:28.970Z', '2026-02-18T14:32:28.970Z', 1, 1, 'dddddddd-dddd-4ddd-8ddd-ddddddddddd1'), ('44444444-4444-4444-8444-444444444442', 12745127, 'Build overlap detection alerts', 'Implement shared-state overlap checks and alert events when active tickets collide on modules or tags.', 'Use shared_state as deterministic MVP source of truth before coordinator LLM and embeddings in V2.', 'Human PM remains in decision loop for all conflicts in MVP.', 'Supabase SQL, edge function triggers, ticket events', 'System emits blocking alert event and exposes candidate conflicting ticket IDs and overlap reason.', 'SQL + server action + examples in docs/overlap-detection.md', 'ChatGPT Agent', 'urgent', 'review', '22222222-2222-4222-8222-222222222222', '2026-02-18T14:32:28.970Z', '2026-02-18T14:32:28.970Z', 0, 1, 'dddddddd-dddd-4ddd-8ddd-ddddddddddd1'), ('44444444-4444-4444-8444-444444444443', 30184, 'Add Open in menu deep-link handlers', 'Provide platform-specific Open in links for Claude, ChatGPT, Terminal, and Cursor from ticket detail.', 'Support lightweight attach command handoff while preserving ticket-scoped context retrieval.', 'No platform SDK lock-in; use URL patterns and clipboard fallback.', 'Next.js UI, browser APIs, protocol routes', 'PM can launch or copy attach flows from a single menu with clear state indicators.', 'UI component, integration notes, and analytics events.', 'Claude App', 'medium', 'complete', '11111111-1111-4111-8111-111111111111', '2026-02-18T14:32:28.970Z', '2026-02-18T14:32:28.970Z', 0, 1, 'dddddddd-dddd-4ddd-8ddd-ddddddddddd1'), ('44444444-4444-4444-8444-444444444444', 15206256, 'Mobile-first PM inbox layout', 'Design ticket conversation list that surfaces blocked agents and pending PM questions first.', 'Direct-message first UX with ticket thumbnail, phase chip, and last event preview.', 'Must keep parity with desktop filters and status transitions.', 'Next.js, Tailwind, Supabase realtime', 'Inbox list is responsive and preserves ticket context isolation and quick actions.', 'Responsive page and component set with accessibility checks.', 'Cursor', 'high', 'blocked', '33333333-3333-4333-8333-333333333333', '2026-02-18T14:32:28.970Z', '2026-02-18T14:32:28.970Z', 0, 1, 'dddddddd-dddd-4ddd-8ddd-ddddddddddd1');
SELECT setval('"public"."tickets_ticket_sequence_seq"'::regclass, (SELECT MAX("ticket_sequence") FROM "public"."tickets"));
